import 'user.details.model.dart';

class AgentModell {
  int? id;
  String? title;
  String? bio;
  dynamic licenseNumber;
  String? company;
  UserModel? user;

  AgentModell({
    this.id,
    this.title,
    this.bio,
    this.licenseNumber,
    this.company,
    this.user,
  });

  factory AgentModell.(
    Map<String, dynamic> json,
  ) {
    return AgentModell(
      id: json['id'] as int?,
      title: json['title'] as String?,
      bio: json['bio'] as String?,
      licenseNumber: json['license_number'] as dynamic,
      company: json['company'] as String?,
      user: json['user'] == null
          ? null
          : UserModel.(
              json['user'] as Map<String, dynamic>,
            ),
    );
  }

  Map<String, dynamic>
  () {
    return {
      'id': id,
      'title': title,
      'bio': bio,
      'license_number': licenseNumber,
      'company': company,
      'user': user
          ?.(),
    };
  }
}
